  ('judicial-cf446b4c-moex-00274', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列判決對於行為人所為易科罰金之敘述，何者錯誤？', '["判處甲拘役50日，得易科罰金以新臺幣1000元折算1日", "判處乙拘役40日，得易科罰金以新臺幣2000元折算1日", "判處丙拘役30日，得易科罰金以新臺幣3000元折算1日", "判處丁拘役20日，得易科罰金以新臺幣4000元折算1日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00275', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何種情況，成立刑法第168條偽證罪？', '["證人甲對案情無重要關係事項，故意為虛偽供述", "證人乙記憶有誤，仍依其記憶而為供述，未料該供述不符實情", "證人丙於法院審理時，針對案情重要事項，故意虛偽供述後，始行具結", "證人丁為13歲之人而虛偽供述"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00276', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何種情形，非屬報請假釋出獄之要件？', '["犯最輕本刑5年以上之罪，於徒刑執行期間接受輔導或治療後，經評估其再犯危險低", "有悛悔實據", "受無期徒刑之執行者，其執行逾25年", "受有期徒刑之執行者，其執行逾二分之一且已滿6個月"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00277', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關刑法第121條不違背職務賄賂罪，下列敘述何者錯誤？', '["行為態樣中所謂之「要求」，係為請求給付賄賂之表示，只要一經請求即為既遂，不以相對人允諾 為必要", "行為態樣中所謂之「期約」，係指雙方意思表示已達合致，縱行賄者尚未交付賄賂，仍不影響犯罪 之成立", "「期約」行為並不以賄賂之金額、數量或內容完全確定為必要", "本罪不以有對價關係存在為必要"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00278', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲招待監所管理員乙上色情酒店，要求乙夾帶毒品給受刑人A，乙同意甲之要求而欣然接受招待，但 嗣後並未夾帶毒品給A，下列敘述何者錯誤？', '["甲成立刑法第122條第3項違背職務行賄罪", "乙成立刑法第122條第1項違背職務受賄罪", "乙未為違背職務行為，故不成立違背職務受賄罪", "性招待亦屬賄賂或不正利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00279', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於藏匿人犯及湮滅證據罪章之各項敘述，下列何者錯誤？', '["本罪章保護法益為本國司法之運作", "刑法第165條所湮滅之證據，限於關係他人刑事被告案件之證據", "偽造關係自己民事被告案件之證據，不成立本罪", "與犯人有3親等姻親關係之人，因圖利犯人而犯第164條之罪，得減輕或免除其刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00280', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲殺害丙，甲遭羈押後，為避免刑事訴追，甲遂教唆律師乙將殺丙所用之兇刀及血衣棄置於水圳內， 有關甲、乙之刑責，下列敘述何者正確？', '["甲不成立犯罪", "甲成立湮滅刑事證據罪之教唆犯", "乙成立湮滅刑事證據罪之幫助犯", "乙成立湮滅刑事證據罪之間接正犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00281', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何者不成立刑法第132條公務員洩漏國防以外秘密罪？', '["國立大學學生會會長在網站上公開校務會議紀錄", "公務員洩露職掌之公共工程標案底價予特定廠商", "警察洩露秘密證人之個人資料予徵信業者", "檢察官於執行搜索前，向特定媒體透露將會搜索某特定廠商辦公室"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00282', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於刑法第132條洩漏國防以外秘密罪，下列敘述何者正確？', '["本罪之處罰，以公務員為限", "本罪之處罰，以故意犯為限", "本罪之處罰，以既遂犯為限", "本罪之處罰，以繼續犯為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00283', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於刑法第135條第1項之妨害公務罪，下列敘述何者正確？', '["妨害公務罪所保護的法益是公務機關之財產法益", "只要對公務員施加強暴、脅迫，不問該公務員是否依法執行職務，均可成立本罪", "公務員所執行之職務必須因行為人之強暴、脅迫行為而無法執行，才成立本罪", "不配合公務員要求，但無強暴、脅迫行為者，不成立本罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
